import socket
import threading
import json
import math

HOST = '127.0.0.1'
PORT = 65432

clients = []
player_states = {}

def handle_client(conn, addr):
    print(f"Connected by {addr}")
    clients.append(conn)

    try:
        while True:
            data = conn.recv(1024)
            if not data:
                break
            process_data(data, conn)
    finally:
        clients.remove(conn)
        conn.close()

def process_data(data, conn):
    player_data = json.loads(data.decode('utf-8'))
    player_id = player_data['id']
    
    player_states[player_id] = player_data
    send_game_state()

def send_game_state():
    game_state = json.dumps(player_states)
    for client in clients:
        try:
            client.sendall(game_state.encode('utf-8'))
        except Exception as e:
            print(f"Error sending data: {e}")

def distance(pos1, pos2):
    return math.sqrt((pos1['x'] - pos2['x']) ** 2 + (pos1['y'] - pos2['y']) ** 2)

def run_server():
    with socket.socket(socket.AF_INET, socket.SOCK_STREAM) as s:
        s.bind((HOST, PORT))
        s.listen()
        print("Server started, waiting for connections...")
        while True:
            conn, addr = s.accept()
            threading.Thread(target=handle_client, args=(conn, addr)).start()

if __name__ == "__main__":
    run_server()